// === Sidebar Event Bindings: Filters, navigation, settings, open/close ===

/**
 * Global view switcher accessible from all modules
 */
let viewHistory = ['history']; // Navigation stack

/**
 * Synchronizes all UI controls (toggles, inputs, dropdowns) with the current 
 * in-memory global state variables. Used for instant updates after backup restores.
 */
function syncSettingsUI() {
    // 0. Syncing based on current selectedDayFilter (no forced reset to 'today' here)

    // 1. Toggles
    const shortsToggle = document.getElementById("shorts-blocker-toggle");
    if (shortsToggle) shortsToggle.checked = shortsBlockerSettings.enabled;

    const dislikeToggle = document.getElementById("dislike-count-toggle");
    if (dislikeToggle) dislikeToggle.checked = dislikeCountSettings.enabled;

    const breakToggle = document.getElementById("break-enabled-toggle");
    if (breakToggle) breakToggle.checked = breakSettings.enabled;

    const backupEnabledToggle = document.getElementById("backup-enabled-toggle");
    if (backupEnabledToggle) backupEnabledToggle.checked = backupSettings.enabled;

    const backupOnCloseToggle = document.getElementById("backup-on-close-toggle");
    if (backupOnCloseToggle) backupOnCloseToggle.checked = backupSettings.backupOnClose;

    // 2. Numeric & Text Inputs
    const intervalValue = document.getElementById("interval-value");
    if (intervalValue) intervalValue.value = breakSettings.intervalMinutes;

    const workUrlInput = document.getElementById("setting-work-url");
    if (workUrlInput) workUrlInput.value = breakSettings.workUrl;

    const maxBackupsValue = document.getElementById("max-backups-value");
    if (maxBackupsValue) maxBackupsValue.value = backupSettings.maxBackups || 10;

    // 3. Custom Dropdowns
    const syncDropdown = (id, value, map) => {
        const dropdown = document.getElementById(id);
        if (!dropdown) return;
        dropdown.dataset.value = value;
        const triggerSpan = dropdown.querySelector(".dropdown-trigger span");
        if (triggerSpan) {
          triggerSpan.textContent = map[value] || (value + " Days");
        }
        
        const items = dropdown.querySelectorAll(".dropdown-item");
        items.forEach(item => {
            item.classList.toggle("active", String(item.dataset.value) === String(value));
        });
    };

    syncDropdown("backup-interval-dropdown", backupSettings.intervalHours, {
        1: "Every Hour", 6: "Every 6 Hours", 12: "Every 12 Hours", 24: "Every Day", 168: "Every Week"
    });

    syncDropdown("retention-duration-dropdown", retentionSettings.duration, {
        7: "7 Days", 15: "15 Days", 30: "30 Days", 90: "3 Months", 180: "6 Months", 365: "1 Year", "-1": "Unlimited"
    });

    syncDropdown("history-period-dropdown", selectedDayFilter, {});

    // 4. Special internal UI syncs
    if (typeof syncHistoryPresets === 'function') syncHistoryPresets();
    if (typeof updateDateLabel === 'function') updateDateLabel();
}

/**
 * Formats a date or preset label for the UI (e.g., "Apr 7, 2026", "Today", or "Last 30 Days").
 */
const formatDateLabel = (value) => {
    const map = {
        "today": "Today", "yesterday": "Yesterday", "7days": "Last 7 Days", "15days": "Last 15 Days", 
        "30days": "Last 30 Days", "90days": "Last 3 Months", "180days": "Last 6 Months", "365days": "Last Year", "all": "All Time"
    };

    if (map[value]) return map[value];

    // Check if it's a specific date YYYY-MM-DD
    const parts = String(value).split("-").map(Number);
    if (parts.length === 3 && !parts.some(isNaN)) {
        const d = new Date(parts[0], parts[1] - 1, parts[2]);
        return d.toLocaleDateString(undefined, {
            month: "short",
            day: "numeric",
            year: "numeric",
        });
    }

    if (String(value).endsWith("days")) {
        return `Last ${parseInt(value, 10)} Days`;
    }

    return value;
};

/**
 * Updates the current date label in the history view and synchronizes the period dropdown.
 */
const updateDateLabel = () => {
    const formatted = formatDateLabel(selectedDayFilter);
    
    // 1. Update side navigation label
    const sideLabel = document.querySelector(".current-date-label");
    if (sideLabel) sideLabel.textContent = formatted;

    // 2. Update period dropdown trigger text
    const histDropdown = document.getElementById("history-period-dropdown");
    if (histDropdown) {
        histDropdown.dataset.value = selectedDayFilter;
        const triggerSpan = histDropdown.querySelector(".dropdown-trigger span");
        if (triggerSpan) {
            // Mapping for dropdown specific labels (e.g. "All History" instead of "All Time")
            const dropdownLabels = { "all": "All History" };
            triggerSpan.textContent = dropdownLabels[selectedDayFilter] || formatted;
        }

        // Update active class on items
        const items = histDropdown.querySelectorAll(".dropdown-item");
        items.forEach(item => {
            item.classList.toggle("active", String(item.dataset.value) === String(selectedDayFilter));
        });
    }
};

/**
 * Syncs the history period dropdown items with data retention settings.
 */
const syncHistoryPresets = () => {
    const dropdown = document.getElementById("history-period-dropdown");
    if (!dropdown) return;
    
    const duration = retentionSettings.duration;
    const items = dropdown.querySelectorAll(".dropdown-item");
    
    items.forEach(item => {
        const val = item.dataset.value;
        if (val === 'today' || val === 'yesterday' || val === 'all') {
            item.style.display = 'block';
            return;
        }
        
        const days = parseInt(val, 10);
        if (duration === -1 || days <= duration) {
            item.style.display = 'block';
        } else {
            item.style.display = 'none';
        }
    });

    // Update Special chip label
    const specialItem = dropdown.querySelector('.dropdown-item.special');
    if (specialItem) {
        specialItem.textContent = duration === -1 ? "Unlimited History" : (duration + " Days History");
    }
};



function switchView(viewName) {
    // Push to history stack (avoid duplicates at top)
    if (viewHistory[viewHistory.length - 1] !== viewName) {
        viewHistory.push(viewName);
        // Keep stack manageable
        if (viewHistory.length > 20) viewHistory.shift();
    }
    _switchViewInternal(viewName);
}

function _switchViewInternal(viewName) {
    activeView = viewName;
    const hView = document.getElementById("history-view");
    const aView = document.getElementById("analytics-view");
    const sView = document.getElementById("settings-view");
    const hFilters = document.getElementById("stats-header-filters");

    if (hView) hView.style.display = viewName === "history" ? "block" : "none";
    if (aView)
      aView.style.display = viewName === "analytics" ? "block" : "none";
    if (sView) sView.style.display = viewName === "settings" ? "block" : "none";
    if (hFilters)
      hFilters.style.display = "block";
    
    const toggleStrip = document.getElementById("history-filter-toggle");
    if (toggleStrip)
      toggleStrip.style.display = "flex";

    const bView = document.getElementById("backup-view");
    if (bView) bView.style.display = viewName === "backup" ? "block" : "none";

    const cdView = document.getElementById("channel-distribution-view");
    if (cdView) cdView.style.display = viewName === "channel-distribution" ? "block" : "none";

    const cPopover = document.getElementById("calendar-popover");
    if (cPopover) cPopover.style.display = "none";

    // Update universal view title bar
    const viewTitleMap = {
        "history": "Watch History",
        "analytics": "Analytics",
        "channel-distribution": "Channel Distribution",
        "backup": "Backup & Restore",
        "settings": "Settings"
    };
    const titleText = document.getElementById("view-title-text");
    const backBtn = document.getElementById("view-back-btn");
    if (titleText) titleText.textContent = viewTitleMap[viewName] || viewName;
    if (backBtn) {
        // Always show back button per user request
        backBtn.style.display = "flex";
        
        // Update opacity to indicate if there's history to walk back into
        backBtn.style.opacity = viewHistory.length > 1 ? "1" : "0.5";
        
        backBtn.onclick = (e) => {
            e.stopPropagation();
            // Pop the current view off the stack
            if (viewHistory.length > 1) {
                viewHistory.pop(); // remove current
                const prev = viewHistory[viewHistory.length - 1];
                _switchViewInternal(prev);
            } else {
                // If on root, ensure we stay on history or perform a subtle UI feedback
                // Providing a consistent "Back" experience as requested
                _switchViewInternal("history");
            }
        };
    }

    // Update Button Active States
    ["nav-history", "nav-analytics", "nav-backup", "nav-settings"].forEach((id) => {
      const navBtn = document.getElementById(id);
      if (navBtn) navBtn.classList.toggle("active", id === `nav-${viewName}`);
    });

    if (typeof renderStats === 'function') renderStats();
}

function bindSidebarEvents(sidebar, btn, dragStatus) {
  // Date Navigator & Calendar Logic
  let calendarDate = new Date(); // Month/Year currently shown in the calendar popover

  // Handled by top-level updateDateLabel()

  const renderCalendar = () => {
    const container = document.getElementById("calendar-popover");
    if (!container) return;

    const year = calendarDate.getFullYear();
    const month = calendarDate.getMonth();
    const monthName = new Date(year, month).toLocaleString(undefined, {
      month: "long",
    });

    const firstDay = new Date(year, month, 1).getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();
    const todayStr = getDayKey(new Date());
    const selectedStr =
      selectedDayFilter === "today"
        ? todayStr
        : selectedDayFilter === "yesterday"
        ? getDayKey(new Date(Date.now() - 86400000))
        : selectedDayFilter;

    let html = `
      <div class="calendar-header">
        <div class="calendar-month-year">${monthName} ${year}</div>
        <div class="calendar-nav">
          <button id="cal-prev" class="nav-arrow-btn">${icons.prev}</button>
          <button id="cal-next" class="nav-arrow-btn">${icons.next}</button>
        </div>
      </div>
      <div class="calendar-grid">
        <div class="calendar-day-label">Su</div>
        <div class="calendar-day-label">Mo</div>
        <div class="calendar-day-label">Tu</div>
        <div class="calendar-day-label">We</div>
        <div class="calendar-day-label">Th</div>
        <div class="calendar-day-label">Fr</div>
        <div class="calendar-day-label">Sa</div>
    `;

    // Empty slots before first day
    for (let i = 0; i < firstDay; i++) {
      html += '<div class="calendar-day empty"></div>';
    }

    // Days of month
    for (let d = 1; d <= daysInMonth; d++) {
      const dateKey = `${year}-${String(month + 1).padStart(2, "0")}-${String(
        d,
      ).padStart(2, "0")}`;
      const isToday = dateKey === todayStr;
      const isSelected = dateKey === selectedStr;

      html += `
        <div class="calendar-day ${isToday ? "today" : ""} ${
        isSelected ? "selected" : ""
      }" data-date="${dateKey}">
          ${d}
        </div>
      `;
    }

    html += "</div>";
    container.innerHTML = html;

    // Calendar Handlers
    container.querySelector("#cal-prev").onclick = (e) => {
      e.stopPropagation();
      calendarDate.setMonth(calendarDate.getMonth() - 1);
      renderCalendar();
    };
    container.querySelector("#cal-next").onclick = (e) => {
      e.stopPropagation();
      calendarDate.setMonth(calendarDate.getMonth() + 1);
      renderCalendar();
    };
    container.querySelectorAll(".calendar-day:not(.empty)").forEach((el) => {
      el.onclick = (e) => {
        e.stopPropagation();
        selectedDayFilter = el.dataset.date === todayStr ? "today" : el.dataset.date;
        container.style.display = "none";
        updateDateLabel();
        renderStats();
      };
    });
  };

  const trigger = document.getElementById("calendar-trigger");
  const popover = document.getElementById("calendar-popover");
  if (trigger && popover) {
    trigger.onclick = (e) => {
      e.stopPropagation();
      const isVisible = popover.style.display === "block";
      popover.style.display = isVisible ? "none" : "block";
      if (!isVisible) renderCalendar();
    };
  }

  const prevBtn = document.getElementById("date-prev");
  const nextBtn = document.getElementById("date-next");

  const shiftDate = (offset) => {
    let current;
    if (selectedDayFilter === "today") {
      current = new Date();
    } else if (selectedDayFilter === "yesterday") {
      current = new Date(Date.now() - 86400000);
    } else if (selectedDayFilter === "all" || selectedDayFilter.endsWith("days")) {
      current = new Date();
    } else {
      const parts = selectedDayFilter.split("-").map(Number);
      if (parts.length === 3 && !parts.some(isNaN)) {
        current = new Date(parts[0], parts[1] - 1, parts[2]);
      } else {
        current = new Date();
      }
    }
    current.setDate(current.getDate() + offset);
    
    const newKey = getDayKey(current);
    selectedDayFilter = (newKey === getDayKey(new Date())) ? "today" : newKey;
    updateDateLabel();
    renderStats();
  };

  if (prevBtn) prevBtn.onclick = (e) => { e.stopPropagation(); shiftDate(-1); };
  if (nextBtn) nextBtn.onclick = (e) => { e.stopPropagation(); shiftDate(1); };

  // History Period Dropdown Logic
  const histDropdown = document.getElementById("history-period-dropdown");
  if (histDropdown) {
    const trigger = histDropdown.querySelector(".dropdown-trigger");
    const items = histDropdown.querySelectorAll(".dropdown-item");

    trigger.onclick = (e) => {
      e.stopPropagation();
      const isOpen = histDropdown.classList.contains("open");
      document.querySelectorAll(".custom-dropdown.open").forEach((d) => {
        if (d !== histDropdown) d.classList.remove("open");
      });
      histDropdown.classList.toggle("open");
    };

    items.forEach((item) => {
      item.onclick = (e) => {
        e.stopPropagation();
        selectedDayFilter = item.dataset.value;
        histDropdown.classList.remove("open");
        updateDateLabel();
        renderStats();
      };
    });
  }

  // Initial syncs
  syncHistoryPresets();
  updateDateLabel();

  // View Navigation Logic

  const attachNav = (id, view) => {
    const el = document.getElementById(id);
    if (el)
      el.onclick = (e) => {
        e.stopPropagation();
        switchView(view);
      };
  };

  attachNav("nav-history", "history");
  attachNav("nav-analytics", "analytics");
  attachNav("nav-settings", "settings");

  const navBackup = document.getElementById("nav-backup");
  if (navBackup) {
    navBackup.onclick = (e) => {
      e.stopPropagation();
      switchView("backup");
      renderBackups();
    };
  }

  const backToSettings = document.getElementById("back-to-settings");
  if (backToSettings) {
    backToSettings.onclick = (e) => {
      e.stopPropagation();
      switchView("settings");
    };
  }




  const navToChannels = document.getElementById("nav-to-channels");
  if (navToChannels) {
    navToChannels.onclick = (e) => {
      e.stopPropagation();
      switchView("channel-distribution");
    };
  }

  // Remove the old nav-backup-view button listener (no longer in HTML)

  // Settings Controls
  const shortsToggle = document.getElementById("shorts-blocker-toggle");
  if (shortsToggle) {
    shortsToggle.onchange = (e) => {
      e.stopPropagation();
      shortsBlockerSettings.enabled = shortsToggle.checked;
      saveShortsBlockerSettings();
      applyShortsBlockerState();
    };
  }

  const dislikeToggle = document.getElementById("dislike-count-toggle");
  if (dislikeToggle) {
    dislikeToggle.onchange = (e) => {
      e.stopPropagation();
      console.log("YTT: Dislike toggled:", dislikeToggle.checked);
      dislikeCountSettings.enabled = dislikeToggle.checked;
      saveDislikeCountSettings();
      // Apply state immediately, force-fetching if enabled
      applyDislikeCountState(dislikeToggle.checked);
    };
  }

  const breakToggle = document.getElementById("break-enabled-toggle");
  if (breakToggle) {
    breakToggle.onchange = (e) => {
      e.stopPropagation();
      breakSettings.enabled = breakToggle.checked;
      saveBreakSettings();
      if (!breakSettings.enabled) {
        continuousWatchStart = null;
        breakModalShown = false;
      }
    };
  }

  const workUrlInput = document.getElementById("setting-work-url");
  if (workUrlInput) {
    workUrlInput.onchange = (e) => {
      let url = workUrlInput.value.trim();
      if (url && !url.startsWith("http")) url = "https://" + url;
      breakSettings.workUrl = url || "https://www.google.com";
      saveBreakSettings();
    };
  }

  const intervalMinus = document.getElementById("interval-minus");
  const intervalPlus = document.getElementById("interval-plus");
  const intervalValue = document.getElementById("interval-value");

  if (intervalMinus) {
    intervalMinus.onclick = (e) => {
      e.stopPropagation();
      breakSettings.intervalMinutes = Math.max(
        1,
        breakSettings.intervalMinutes - 1,
      );
      if (intervalValue) intervalValue.value = breakSettings.intervalMinutes;
      saveBreakSettings();
    };
  }
  if (intervalPlus) {
    intervalPlus.onclick = (e) => {
      e.stopPropagation();
      breakSettings.intervalMinutes = Math.min(
        120,
        breakSettings.intervalMinutes + 1,
      );
      if (intervalValue) intervalValue.value = breakSettings.intervalMinutes;
      saveBreakSettings();
    };
  }
  if (intervalValue) {
    intervalValue.onchange = (e) => {
      let val = parseInt(intervalValue.value, 10);
      if (isNaN(val) || val < 1) val = 1;
      if (val > 120) val = 120;
      breakSettings.intervalMinutes = val;
      intervalValue.value = val;
      saveBreakSettings();
    };
  }

  // Backup Settings
  const backupEnabledToggle = document.getElementById("backup-enabled-toggle");
  if (backupEnabledToggle) {
    backupEnabledToggle.onchange = (e) => {
      e.stopPropagation();
      backupSettings.enabled = backupEnabledToggle.checked;
      saveBackupSettings();
    };
  }

  const backupOnCloseToggle = document.getElementById("backup-on-close-toggle");
  if (backupOnCloseToggle) {
    backupOnCloseToggle.onchange = (e) => {
      e.stopPropagation();
      backupSettings.backupOnClose = backupOnCloseToggle.checked;
      saveBackupSettings();
    };
  }

  const backupDropdown = document.getElementById("backup-interval-dropdown");
  if (backupDropdown) {
    const trigger = backupDropdown.querySelector(".dropdown-trigger");
    const menu = backupDropdown.querySelector(".dropdown-menu");
    const items = backupDropdown.querySelectorAll(".dropdown-item");

    trigger.onclick = (e) => {
      e.stopPropagation();
      const isOpen = backupDropdown.classList.contains("open");
      // Close any other open dropdowns first (if we had more)
      document
        .querySelectorAll(".custom-dropdown.open")
        .forEach((d) => d.classList.remove("open"));
      if (!isOpen) backupDropdown.classList.add("open");
    };

    items.forEach((item) => {
      item.onclick = (e) => {
        e.stopPropagation();
        const value = parseInt(item.dataset.value, 10);
        const label = item.textContent;

        // Update state
        backupSettings.intervalHours = value;
        saveBackupSettings();

        // Update UI
        backupDropdown.dataset.value = value;
        trigger.querySelector("span").textContent = label;
        items.forEach((i) => i.classList.remove("active"));
        item.classList.add("active");

        // Close
        backupDropdown.classList.remove("open");
      };
    });
  }

  const retentionDropdown = document.getElementById("retention-duration-dropdown");
  if (retentionDropdown) {
    const trigger = retentionDropdown.querySelector(".dropdown-trigger");
    const menu = retentionDropdown.querySelector(".dropdown-menu");
    const items = retentionDropdown.querySelectorAll(".dropdown-item");

    trigger.onclick = (e) => {
      e.stopPropagation();
      const isOpen = retentionDropdown.classList.contains("open");
      document
        .querySelectorAll(".custom-dropdown.open")
        .forEach((d) => d.classList.remove("open"));
      if (!isOpen) retentionDropdown.classList.add("open");
    };

    items.forEach((item) => {
      item.onclick = (e) => {
        e.stopPropagation();
        const value = parseInt(item.dataset.value, 10);
        const label = item.textContent;

        // Update state
        retentionSettings.duration = value;
        saveRetentionSettings();

        // Update UI
        retentionDropdown.dataset.value = value;
        trigger.querySelector("span").textContent = label;
        items.forEach((i) => i.classList.remove("active"));
        item.classList.add("active");

        // Sync history filters
        if (typeof syncHistoryPresets === 'function') {
            syncHistoryPresets();
        }

        // Close
        retentionDropdown.classList.remove("open");
      };
    });
  }
  
  const maxBackupsMinus = document.getElementById("max-backups-minus");
  const maxBackupsPlus = document.getElementById("max-backups-plus");
  const maxBackupsValue = document.getElementById("max-backups-value");

  if (maxBackupsMinus) {
    maxBackupsMinus.onclick = (e) => {
      e.stopPropagation();
      backupSettings.maxBackups = Math.max(
        1,
        (backupSettings.maxBackups || 10) - 1,
      );
      if (maxBackupsValue) maxBackupsValue.value = backupSettings.maxBackups;
      saveBackupSettings();
    };
  }
  if (maxBackupsPlus) {
    maxBackupsPlus.onclick = (e) => {
      e.stopPropagation();
      backupSettings.maxBackups = Math.min(
        50,
        (backupSettings.maxBackups || 10) + 1,
      );
      if (maxBackupsValue) maxBackupsValue.value = backupSettings.maxBackups;
      saveBackupSettings();
    };
  }
  if (maxBackupsValue) {
    maxBackupsValue.onchange = (e) => {
      let val = parseInt(maxBackupsValue.value, 10);
      if (isNaN(val) || val < 1) val = 1;
      if (val > 50) val = 50;
      backupSettings.maxBackups = val;
      maxBackupsValue.value = val;
      saveBackupSettings();
    };
  }

  // Close dropdowns on outside click
  document.addEventListener("click", () => {
    document
      .querySelectorAll(".custom-dropdown.open")
      .forEach((d) => d.classList.remove("open"));
  });

  const createBackupBtn = document.getElementById("create-manual-backup");
  const deleteBtn = document.getElementById("delete-all-backups");
  if (deleteBtn) {
    deleteBtn.onclick = () => {
        showConfirmModal({
            title: "Clear All Backups?",
            message: "This will permanently delete all stored snapshots in the local database. This action cannot be undone.",
            confirmText: "Clear All",
            cancelText: "Cancel",
            icon: "🗑️",
            onConfirm: () => {
                safeSendMessage({ action: "DELETE_ALL_BACKUPS" }, (response) => {
                    if (response && response.success) {
                        renderBackups();
                    } else {
                        alert("Failed to clear backups: " + (response ? response.error : "Unknown error"));
                    }
                });
            }
        });
    };
  }

  // Import JSON Click
  const importBtn = document.getElementById("import-backup-json");
  const fileInput = document.getElementById("backup-file-input");

  if (importBtn && fileInput) {
    importBtn.onclick = (e) => {
      e.stopPropagation();
      fileInput.click();
    };

    fileInput.onchange = (e) => {
      const file = e.target.files[0];
      if (!file) return;

      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const importedData = JSON.parse(event.target.result);
          
          // Basic validation
          if (!importedData.allHistory && !importedData.shortsBlockerSettings) {
             throw new Error("Invalid backup file format");
          }

          showConfirmModal({
            title: "Import Backup?",
            message: "This will overwrite your current history and settings. Are you sure?",
            confirmText: "Import & Restore",
            cancelText: "Cancel",
            icon: "📥",
            onConfirm: () => {
              importBtn.disabled = true;
              importBtn.textContent = "Importing...";

              safeSendMessage({ action: "IMPORT_BACKUP", clientData: importedData }, (response) => {
                importBtn.disabled = false;
                importBtn.textContent = "Import JSON";
                fileInput.value = ""; // Reset input

                if (response && response.success) {
                   // Refresh everything instantly without reload
                   // Explicitly update local state variables from response to avoid race conditions
                   if (response.settings) {
                       const s = response.settings;
                       if (s.ytt_shorts_settings) shortsBlockerSettings.enabled = s.ytt_shorts_settings.enabled;
                       if (s.ytt_dislike_settings) dislikeCountSettings.enabled = s.ytt_dislike_settings.enabled;
                       if (s.ytt_break_settings) {
                           breakSettings.enabled = s.ytt_break_settings.enabled;
                           breakSettings.intervalMinutes = s.ytt_break_settings.intervalMinutes;
                           breakSettings.workUrl = s.ytt_break_settings.workUrl;
                       }
                       if (s.ytt_backup_settings) backupSettings = { ...backupSettings, ...s.ytt_backup_settings };
                       if (s.ytt_retention_settings) retentionSettings = { ...retentionSettings, ...s.ytt_retention_settings };
                       
                       // Apply live side-effects
                       if (typeof applyShortsBlockerState === 'function') applyShortsBlockerState();
                       if (typeof applyDislikeCountState === 'function') applyDislikeCountState(dislikeCountSettings.enabled);
                   }

                   // Give storage.onChanged and DOM a moment to settle for total reliability
                   setTimeout(() => {
                        selectedDayFilter = 'today'; // Reset filter specifically for imports
                        syncSettingsUI();
                        switchView("history");
                        renderStats();
                        renderBackups();
                   }, 50);
                   
                   // Show success feedback
                   const originalHtml = importBtn.innerHTML;
                   importBtn.textContent = "Imported!";
                   importBtn.style.color = "#2ecc71";
                   setTimeout(() => {
                      importBtn.innerHTML = originalHtml;
                      importBtn.style.color = "";
                   }, 2000);
                } else {
                    showAlertModal({
                        title: "Import Failed",
                        message: response ? response.error : "Unknown error occurred during import.",
                        icon: "❌"
                    });
                }
              });
            }
          });
        } catch (err) {
          showAlertModal({
              title: "Invalid File",
              message: "The selected file is not a valid YouTube Time Tracker backup. Please check the JSON format.",
              icon: "⚠️"
          });
          fileInput.value = "";
        }
      };
      reader.readAsText(file);
    };
  }

  if (createBackupBtn) {
    createBackupBtn.onclick = (e) => {
      e.stopPropagation();
      createBackupBtn.disabled = true;
      const originalHtml = createBackupBtn.innerHTML;
      createBackupBtn.textContent = "Backing up...";

      safeSendMessage({ action: "CREATE_BACKUP_MANUAL" }, () => {
        createBackupBtn.disabled = false;
        createBackupBtn.innerHTML = originalHtml;
        renderBackups();
      });
    };
  }

  // Clear Data Action
  const clearDataBtn = document.getElementById("clear-all-data");
  if (clearDataBtn) {
    clearDataBtn.onclick = (e) => {
      e.stopPropagation();

      showConfirmModal({
        title: "Clear All Data?",
        message:
          "Are you sure you want to delete all watch history and reset all settings? This action cannot be undone.",
        confirmText: "Clear All",
        cancelText: "Cancel",
        icon: "🗑️",
        onConfirm: () => {
          clearAllData();

          // Update UI elements immediately
          const intervalVal = document.getElementById("interval-value");
          if (intervalVal) intervalVal.value = breakSettings.intervalMinutes;

          const sToggle = document.getElementById("shorts-blocker-toggle");
          if (sToggle) sToggle.checked = shortsBlockerSettings.enabled;

          const dToggle = document.getElementById("dislike-count-toggle");
          if (dToggle) dToggle.checked = dislikeCountSettings.enabled;

          const bToggle = document.getElementById("break-enabled-toggle");
          if (bToggle) bToggle.checked = breakSettings.enabled;

          const wUrlInput = document.getElementById("setting-work-url");
          if (wUrlInput) wUrlInput.value = breakSettings.workUrl;

          // Show history view to indicate completion
          switchView("history");
          renderStats();

          // Visual feedback on the button
          const originalHtml = clearDataBtn.innerHTML;
          clearDataBtn.textContent = "Data Cleared!";
          clearDataBtn.style.background = "#2ecc71";
          clearDataBtn.style.color = "white";
          clearDataBtn.style.borderColor = "#2ecc71";
          setTimeout(() => {
            clearDataBtn.innerHTML = originalHtml;
            clearDataBtn.style.background = "";
            clearDataBtn.style.color = "";
            clearDataBtn.style.borderColor = "";
          }, 2000);
        },
      });
    };
  }

  // Filter Section Toggle Logic
  const toggleBtn = document.getElementById("toggle-filter-btn");
  const subheader = document.getElementById("stats-header-filters");
  const toggleStrip = document.getElementById("history-filter-toggle");

  if (toggleBtn && subheader) {
    const toggleFilters = (forceState) => {
        const isCollapsed = subheader.classList.contains("collapsed");
        const shouldCollapse = forceState !== undefined ? !forceState : !isCollapsed;
        
        subheader.classList.toggle("collapsed", shouldCollapse);
        toggleBtn.classList.toggle("expanded", !shouldCollapse);
        
        // Update icon based on state
        toggleBtn.innerHTML = shouldCollapse ? icons.chevron_down : icons.chevron_up;
    };

    toggleBtn.onclick = (e) => {
        e.stopPropagation();
        toggleFilters();
    };

    // "Drag down" feel - simple version: click on strip also toggles
    if (toggleStrip) {
        let startY = 0;
        toggleStrip.onmousedown = (e) => {
            startY = e.clientY;
            
            const onMouseMove = (moveEvent) => {
                const dy = moveEvent.clientY - startY;
                if (dy > 20) { // Dragged down enough
                    toggleFilters(true); // Expand
                    cleanup();
                } else if (dy < -20) { // Dragged up enough
                    toggleFilters(false); // Collapse
                    cleanup();
                }
            };
            
            const cleanup = () => {
                document.removeEventListener("mousemove", onMouseMove);
                document.removeEventListener("mouseup", cleanup);
            };
            
            document.addEventListener("mousemove", onMouseMove);
            document.addEventListener("mouseup", cleanup);
        };
        
        // Also allow clicking the strip itself to toggle
        toggleStrip.onclick = (e) => {
            if (e.target === toggleStrip) {
                toggleFilters();
            }
        };
    }
  }

  // Toggle sidebar open/close
  btn.onclick = (e) => {
    if (dragStatus.isDragging) return; // Don't toggle if we were dragging
    e.stopPropagation();
    isStatsOpen = !isStatsOpen;

    sidebar.classList.toggle("open", isStatsOpen);
    btn.classList.toggle("active", isStatsOpen);

    if (isStatsOpen) {
      document.body.classList.add("stats-sidebar-active");
      document.body.style.overflow = "hidden";
      renderStats();
    } else {
      document.body.classList.remove("stats-sidebar-active");
      document.body.style.overflow = "";
    }
  };

  const closeBtn = document.getElementById("close-stats");
  if (closeBtn) {
    closeBtn.onclick = (e) => {
      e.stopPropagation();
      isStatsOpen = false;
      sidebar.classList.remove("open");
      btn.classList.remove("active");
      document.body.classList.remove("stats-sidebar-active");
      document.body.style.overflow = "";
    };
  }

  // Close on escape
  window.addEventListener("keydown", (e) => {
    if (e.key === "Escape" && isStatsOpen) {
      isStatsOpen = false;
      sidebar.classList.remove("open");
      btn.classList.remove("active");
      document.body.classList.remove("stats-sidebar-active");
      document.body.style.overflow = "";
    }
  });

  // Scroll Listener for Infinite History
  const statsBody = sidebar.querySelector(".stats-body");
  if (statsBody) {
    statsBody.onscroll = () => {
        if (activeView !== 'history') return;
        
        // Trigger if we are 200px from the bottom
        const threshold = 200;
        const remaining = statsBody.scrollHeight - (statsBody.scrollTop + statsBody.clientHeight);
        
        if (remaining < threshold) {
            appendHistoryBatch();
        }
    };
  }

  // Close on click outside
  document.addEventListener("click", (e) => {
    if (popover && !popover.contains(e.target) && e.target !== trigger) {
        popover.style.display = "none";
    }
    
    if (isStatsOpen && !sidebar.contains(e.target) && e.target !== btn) {
      isStatsOpen = false;
      sidebar.classList.remove("open");
      btn.classList.remove("active");
      document.body.classList.remove("stats-sidebar-active");
      document.body.style.overflow = "";
    }
  });

  // Sidebar hover logic (simplified as global lock is now primary)
  sidebar.onmouseenter = () => {
    // Already handled by global lock if open
  };
  sidebar.onmouseleave = () => {
    if (!isStatsOpen) document.body.style.overflow = "";
  };

  // Initial UI sync
  switchView(activeView);
  updateDateLabel();
}

/**
 * Fetches and renders the list of backups present in IndexedDB.
 */
function renderBackups() {
  const list = document.getElementById("backup-history-list");
  if (!list) return;

  safeSendMessage({ action: "GET_BACKUPS" }, (backups) => {
    if (!backups || backups.length === 0) {
      list.innerHTML =
        '<li class="loading-placeholder">No backups found yet.</li>';
      return;
    }

    list.innerHTML = "";
    backups.forEach((b) => {
      const item = document.createElement("li");
      item.className = "backup-item";
      item.innerHTML = `
                <div class="backup-lead">
                    ${icons.backup}
                </div>
                <div class="backup-info">
                    <span class="backup-date">${b.dateString}</span>
                    <span class="backup-meta">Snapshot - YouTube History</span>
                </div>
                <div class="backup-actions">
                    <button class="backup-btn restore-btn" title="Restore this Backup" data-id="${b.id}">
                        ${icons.restore}
                    </button>
                    <button class="backup-btn download-btn" title="Download as JSON" data-id="${b.id}">
                        ${icons.download}
                    </button>
                    <button class="backup-btn delete-btn" title="Delete Backup" data-id="${b.id}">
                        ${icons.close}
                    </button>
                </div>
            `;

      // Restore Action
      item.querySelector(".restore-btn").onclick = (e) => {
        e.stopPropagation();
        const id = e.currentTarget.dataset.id;
        showConfirmModal({
          title: "Restore this Backup?",
          message: "This will completely overwrite your current history and settings with data from this snapshot. Are you sure?",
          confirmText: "Restore Now",
          cancelText: "Cancel",
          icon: "🔄",
          onConfirm: () => {
             safeSendMessage({ action: "RESTORE_BACKUP", id: id }, (response) => {
                 if (response && response.success) {
                    // Success feedback: sync UI instantly
                    // Explicitly update local state variables from response to avoid race conditions
                    if (response.settings) {
                        const s = response.settings;
                        if (s.ytt_shorts_settings) shortsBlockerSettings.enabled = s.ytt_shorts_settings.enabled;
                        if (s.ytt_dislike_settings) dislikeCountSettings.enabled = s.ytt_dislike_settings.enabled;
                        if (s.ytt_break_settings) {
                            breakSettings.enabled = s.ytt_break_settings.enabled;
                            breakSettings.intervalMinutes = s.ytt_break_settings.intervalMinutes;
                            breakSettings.workUrl = s.ytt_break_settings.workUrl;
                        }
                        if (s.ytt_backup_settings) backupSettings = { ...backupSettings, ...s.ytt_backup_settings };
                        if (s.ytt_retention_settings) retentionSettings = { ...retentionSettings, ...s.ytt_retention_settings };

                        // Apply live side-effects
                        if (typeof applyShortsBlockerState === 'function') applyShortsBlockerState();
                        if (typeof applyDislikeCountState === 'function') applyDislikeCountState(dislikeCountSettings.enabled);
                    }

                    // Give storage.onChanged and DOM a moment to settle for total reliability
                    setTimeout(() => {
                        selectedDayFilter = 'today'; // Reset filter specifically for restores
                        syncSettingsUI();
                        switchView("history");
                        renderStats();
                        renderBackups();
                    }, 50);
                 } else {
                    alert("Failed to restore: " + (response ? response.error : "Unknown error"));
                 }
             });
          }
        });
      };

      // Download Action
      item.querySelector(".download-btn").onclick = (e) => {
        e.stopPropagation();
        const id = e.currentTarget.dataset.id;
        // In extension content scripts, we can't directly use yttDB if it's in a different world,
        // but since we bundled it into content.js, it should be available.
        // However, it's safer to ask background for the full data and then trigger download here.
        chrome.runtime.sendMessage(
          { action: "GET_BACKUPS" },
          (allFullBackups) => {
            // Wait, GET_BACKUPS in background now returns metadata only? 
            // I should have a GET_BACKUP_BY_ID in background.
          },
        );
        // Correct approach: ask background for full data via a new message or use GET_BACKUPS if it returned everything.
        // Actually, my getAllBackups returns metadata only. I need a GET_BACKUP_BY_ID handler.
        
        // Re-routing through background for full data
        safeSendMessage({ action: "GET_BACKUP_FULL", id: id }, (fullBackup) => {
            if (fullBackup) {
                const blob = new Blob([JSON.stringify(fullBackup.data, null, 2)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a');
                a.href = url;
                a.download = `ytt_backup_${id}_${new Date(fullBackup.timestamp).toISOString().split('T')[0]}.json`;
                document.body.appendChild(a);
                a.click();
                document.body.removeChild(a);
                URL.revokeObjectURL(url);
            }
        });
      };

      // Delete Action
      item.querySelector(".delete-btn").onclick = (e) => {
        e.stopPropagation();
        const id = e.currentTarget.dataset.id;
        showConfirmModal({
          title: "Delete Backup?",
          message: "Are you sure you want to remove this backup? This cannot be undone.",
          confirmText: "Delete",
          cancelText: "Cancel",
          icon: "🗑️",
          onConfirm: () => {
             safeSendMessage({ action: "DELETE_BACKUP", id: id }, () => {
                 renderBackups();
             });
          }
        });
      };

      list.appendChild(item);
    });
  });
}


// ─── stats-tracker/sidebar-ui.js ───────────────────────────────── 
// === Stats Sidebar UI: Toggle button, sidebar creation, drag & resize ===
const SCROLLBAR_PADDING = 30;

function injectStatsUI() {
  if (!document.body) return;
  if (document.getElementById("stats-toggle-btn")) return;

  // Tooltip (Global sibling of sidebar)
  if (!document.getElementById("stats-tooltip")) {
    const tooltip = document.createElement("div");
    tooltip.id = "stats-tooltip";
    tooltip.className = "stats-tooltip";
    document.body.appendChild(tooltip);
  }

  // Load position first to avoid "jump" during navigation
  safeStorageGet("ytt_toggle_pos", (data) => {
    if (document.getElementById("stats-toggle-btn")) return;

    // Toggle Button
    const btn = document.createElement("div");
    btn.id = "stats-toggle-btn";
    btn.innerHTML = `
            ${icons.stats_toggle}
            <span id="stats-timer-badge" class="stats-timer-badge" style="display: none;"></span>
        `;
    btn.title = "YouTube Stats Tracker (Drag to Move)";

    const savedPos = data.ytt_toggle_pos || null;

    // Apply saved position BEFORE appending to DOM to prevent flash
    applyPosition(btn, savedPos);
    document.body.appendChild(btn);

    // Events and initialization
    setupSidebarLogic(btn);
  });
}

/**
 * Applies position to the button. Always uses `left` for horizontal
 * placement so the CSS spring transition works correctly.
 */
function applyPosition(btn, savedPos) {
  const padding = 10;
  const btnSize = 54; // matches CSS width/height

  let { top, snapped } = savedPos || {};

  // Default values
  let topNum = parseInt(top, 10);
  if (isNaN(topNum)) topNum = 80;

  // Vertical boundary
  const maxTop = window.innerHeight - btnSize - padding;
  topNum = Math.max(padding, Math.min(maxTop, topNum));

  // Horizontal: always use `left` so CSS transition animates the spring
  let leftNum;
  if (snapped === "right") {
    leftNum = window.innerWidth - btnSize - SCROLLBAR_PADDING;
  } else {
    leftNum = padding;
    snapped = "left";
  }

  btn.style.top = topNum + "px";
  btn.style.left = leftNum + "px";
  btn.style.bottom = "auto";
  btn.style.right = "auto";

  return { top: topNum, snapped };
}

function setupSidebarLogic(btn) {
  const dragStatus = { isDragging: false };
  let currentSnapped = "right"; // default

  // Read initial snapped state from storage
  safeStorageGet("ytt_toggle_pos", (data) => {
    if (data.ytt_toggle_pos && data.ytt_toggle_pos.snapped) {
      currentSnapped = data.ytt_toggle_pos.snapped;
    }
  });

  // On resize/fullscreen: re-read saved position from storage then re-apply
  const handleViewportChange = () => {
    safeStorageGet("ytt_toggle_pos", (data) => {
      const result = applyPosition(btn, data.ytt_toggle_pos || null);
      currentSnapped = result.snapped;
    });
  };

  let resizeTimer;
  window.addEventListener("resize", () => {
    clearTimeout(resizeTimer);
    resizeTimer = setTimeout(handleViewportChange, 150);
  });

  document.addEventListener("fullscreenchange", handleViewportChange);
  document.addEventListener("webkitfullscreenchange", handleViewportChange);

  let startX, startY, btnStartX, btnStartY;

  btn.onmousedown = (e) => {
    dragStatus.isDragging = false;
    startX = e.clientX;
    startY = e.clientY;
    const rect = btn.getBoundingClientRect();
    btnStartX = rect.left;
    btnStartY = rect.top;

    const onMouseMove = (moveEvent) => {
      const dx = moveEvent.clientX - startX;
      const dy = moveEvent.clientY - startY;

      if (Math.abs(dx) > 5 || Math.abs(dy) > 5) {
        dragStatus.isDragging = true;
        btn.classList.add("dragging");

        let newLeft = btnStartX + dx;
        let newTop = btnStartY + dy;

        // Boundary Constraints
        const padding = 10;
        newLeft = Math.max(
          padding,
          Math.min(window.innerWidth - btn.offsetWidth - padding, newLeft),
        );
        newTop = Math.max(
          padding,
          Math.min(window.innerHeight - btn.offsetHeight - padding, newTop),
        );

        btn.style.left = newLeft + "px";
        btn.style.top = newTop + "px";
        btn.style.bottom = "auto";
        btn.style.right = "auto";
      }
    };

    const onMouseUp = () => {
      document.removeEventListener("mousemove", onMouseMove);
      document.removeEventListener("mouseup", onMouseUp);

      if (dragStatus.isDragging) {
        btn.classList.remove("dragging");

        // Springy Edge Snapping — uses `left` so the CSS transition animates
        const rect = btn.getBoundingClientRect();
        const centerX = rect.left + rect.width / 2;
        const padding = 10;
        let snapped;

        if (centerX < window.innerWidth / 2) {
          btn.style.left = padding + "px";
          snapped = "left";
        } else {
          btn.style.left =
            window.innerWidth - rect.width - SCROLLBAR_PADDING + "px";
          snapped = "right";
        }

        currentSnapped = snapped;

        // Save state
        setTimeout(() => {
          safeStorageSet({
            ytt_toggle_pos: {
              top: btn.style.top,
              snapped: snapped,
            },
          });
          // Reset dragging status AFTER the click event has a chance to fire
          dragStatus.isDragging = false;
        }, 200);
      }
    };

    document.addEventListener("mousemove", onMouseMove);
    document.addEventListener("mouseup", onMouseUp);
  };

  // Sidebar
  const sidebar = document.createElement("div");
  sidebar.id = "stats-sidebar";

  // Load and Apply Persisted Width from storage
  safeStorageGet("ytt_sidebar_width", (data) => {
    if (data.ytt_sidebar_width) {
      sidebar.style.width = data.ytt_sidebar_width + "px";
    }
  });

  // Add Resizer Handle
  const resizer = document.createElement("div");
  resizer.className = "sidebar-resizer";
  sidebar.appendChild(resizer);

  // Resizing Logic
  let isResizing = false;
  resizer.onmousedown = (e) => {
    e.preventDefault(); // Prevent text selection start
    isResizing = true;
    document.body.classList.add("yt-shorts-resizing-active");
    sidebar.classList.add("resizing");
    resizer.classList.add("active");

    const startX = e.clientX;
    const startWidth = parseInt(getComputedStyle(sidebar).width, 10);

    const onMouseMove = (moveEvent) => {
      if (!isResizing) return;
      const currentX = moveEvent.clientX;
      const delta = startX - currentX; // Moving left increases width
      let newWidth = startWidth + delta;

      // Constraints
      newWidth = Math.max(300, Math.min(800, newWidth));
      sidebar.style.width = newWidth + "px";
    };

    const onMouseUp = () => {
      isResizing = false;
      document.body.classList.remove("yt-shorts-resizing-active");
      sidebar.classList.remove("resizing");
      resizer.classList.add("active");
      safeStorageSet({
        ytt_sidebar_width: parseInt(sidebar.style.width, 10),
      });
      document.removeEventListener("mousemove", onMouseMove);
      document.removeEventListener("mouseup", onMouseUp);
    };

    document.addEventListener("mousemove", onMouseMove);
    document.addEventListener("mouseup", onMouseUp);
  };

  // Insert sidebar HTML template
  sidebar.insertAdjacentHTML("beforeend", getSidebarHTML());
  document.body.appendChild(sidebar);

  // Bind all events (filters, navigation, settings, open/close)
  bindSidebarEvents(sidebar, btn, dragStatus);
}


// ─── stats-tracker/fullscreen-auto-hide.js ─────────────────────── 
// === Fullscreen Auto-hide: Hide toggle button during fullscreen inactivity ===

let autoHideTimeout = null;
const AUTO_HIDE_DELAY = 3000; // 5 seconds

function setupFullscreenAutoHide() {
    // Listen for fullscreen changes
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    document.addEventListener('webkitfullscreenchange', handleFullscreenChange);

    // Listen for mouse movement to reset timer
    document.addEventListener('mousemove', resetAutoHideTimer);
}

function handleFullscreenChange() {
    const isFullscreen = !!(document.fullscreenElement || document.webkitFullscreenElement);
    const btn = document.getElementById('stats-toggle-btn');
    
    if (!btn) return;

    if (isFullscreen) {
        startAutoHideTimer();
    } else {
        stopAutoHideTimer();
        btn.style.opacity = '1';
        btn.style.pointerEvents = 'auto';
    }
}

function resetAutoHideTimer() {
    const isFullscreen = !!(document.fullscreenElement || document.webkitFullscreenElement);
    if (!isFullscreen) return;

    const btn = document.getElementById('stats-toggle-btn');
    if (btn) {
        btn.style.opacity = '1';
        btn.style.pointerEvents = 'auto';
    }

    startAutoHideTimer();
}

function startAutoHideTimer() {
    stopAutoHideTimer();
    autoHideTimeout = setTimeout(() => {
        const btn = document.getElementById('stats-toggle-btn');
        if (btn && !btn.classList.contains('active')) { // Only hide if sidebar is NOT open
            btn.style.opacity = '0';
            btn.style.pointerEvents = 'none'; // Prevent accidental clicks or hover while hidden
        }
    }, AUTO_HIDE_DELAY);
}

function stopAutoHideTimer() {
    if (autoHideTimeout) {
        clearTimeout(autoHideTimeout);
        autoHideTimeout = null;
    }
}


// ─── stats-tracker/history-render.js ───────────────────────────── 
// === History View Rendering ===

function renderStats() {
    let displayWatchTime = 0;
    let displayVideos = [];
    let displayDuration = 0;
    
    const now = new Date();
    const today = getDayKey(now);
    const yesterday = getDayKey(new Date(now.getTime() - 86400000));
    
    if (selectedDayFilter === 'today') {
        const data = allHistory[today] || { watchTime: 0, activeTime: 0, videos: [], sessionStart: Date.now() };
        displayWatchTime = data.watchTime;
        displayVideos = data.videos;
        displayDuration = data.activeTime || 0;
    } else if (selectedDayFilter === 'yesterday') {
        const data = allHistory[yesterday] || { watchTime: 0, activeTime: 0, videos: [], sessionStart: 0 };
        displayWatchTime = data.watchTime;
        displayVideos = data.videos;
        displayDuration = data.activeTime || 0;
    } else if (selectedDayFilter.endsWith('days')) {
        // Range-based filtering: today, yesterday, 7days, 15days, 30days, etc.
        const daysToInclude = parseInt(selectedDayFilter);
        for (let i = 0; i < daysToInclude; i++) {
            const date = new Date(now.getTime() - i * 86400000);
            const key = getDayKey(date);
            const dayData = allHistory[key];
            if (dayData) {
                displayWatchTime += dayData.watchTime;
                displayVideos = displayVideos.concat(dayData.videos);
                displayDuration += (dayData.activeTime || 0);
            }
        }
    } else if (selectedDayFilter === 'all') {
        Object.values(allHistory).forEach(day => {
            displayWatchTime += day.watchTime;
            displayVideos = displayVideos.concat(day.videos);
            displayDuration += (day.activeTime || 0);
        });
    } else {
        const data = allHistory[selectedDayFilter] || { watchTime: 0, activeTime: 0, videos: [], sessionStart: 0 };
        displayWatchTime = data.watchTime;
        displayVideos = data.videos;
        displayDuration = data.activeTime || 0;
    }

    const getDisplayTitle = () => {
        if (selectedDayFilter === 'today') return 'Watch History (Today)';
        if (selectedDayFilter === 'yesterday') return 'Watch History (Yesterday)';
        if (selectedDayFilter.endsWith('days')) {
            const days = parseInt(selectedDayFilter);
            return `Watch History (Last ${days} Days)`;
        }
        if (selectedDayFilter === 'all') return 'Watch History (All Time)';
        
        const [y, m, d] = selectedDayFilter.split('-').map(Number);
        const date = new Date(y, m - 1, d);
        return `History for ${date.toLocaleDateString(undefined, { month: 'long', day: 'numeric', year: 'numeric' })}`;
    };

    if (activeView === 'history') {
        const titleEl = document.getElementById('history-title');
        if (titleEl) titleEl.textContent = getDisplayTitle();
        const durationEl = document.getElementById('session-duration');
        const watchTimeEl = document.getElementById('total-watch-time');
        const countEl = document.getElementById('videos-count');
        const listEl = document.getElementById('video-history-list');

        // Update basic counts always
        if (durationEl) {
            if (selectedDayFilter === 'today') {
                durationEl.parentElement.style.display = 'flex';
                durationEl.textContent = formatTime(displayDuration);
            } else {
                durationEl.parentElement.style.display = 'none';
            }
        }
        if (watchTimeEl) watchTimeEl.textContent = formatTime(displayWatchTime);
        if (countEl) countEl.textContent = displayVideos.length;

        // Check if we need to rebuild the list structure
        const needsFullRebuild = (activeView !== lastRenderedView || 
                                  selectedDayFilter !== lastRenderedFilter || 
                                  displayVideos.length !== lastVideoCount);

        if (needsFullRebuild && listEl) {
            lastRenderedView = activeView;
            lastRenderedFilter = selectedDayFilter;
            lastVideoCount = displayVideos.length;

            if (displayVideos.length === 0) {
                listEl.innerHTML = '<div style="text-align:center; padding: 40px; color:#666;">No activity recorded for this period.</div>';
                fullSortedVideos = [];
                loadedVideoCount = 0;
            } else {
                // Sort by lastStarted descending (fallback to lastUpdated for existing data)
                fullSortedVideos = displayVideos.slice().sort((a, b) => {
                    const aTime = a.lastStarted || a.lastUpdated || 0;
                    const bTime = b.lastStarted || b.lastUpdated || 0;
                    return bTime - aTime;
                });
                listEl.innerHTML = '';
                loadedVideoCount = 0;
                appendHistoryBatch();
            }
        } else if (listEl && activeView === 'history') {
            // High-frequency UI sync for ALL videos across multiple tabs
            let topVideoUid = null;
            
            // 1. Determine which video SHOULD be at the top
            // Rule: Local video wins if playing, otherwise most recent global starter.
            const localVideo = displayVideos.find(v => v.uid === currentUid);
            if (localVideo && localVideo.isPlaying) {
                topVideoUid = localVideo.uid;
            } else {
                // Find most recently started video across all tabs
                const latestGlobal = [...displayVideos].sort((a, b) => {
                    const aTime = a.lastStarted || a.lastUpdated || 0;
                    const bTime = b.lastStarted || b.lastUpdated || 0;
                    return bTime - aTime;
                })[0];
                if (latestGlobal) topVideoUid = latestGlobal.uid;
            }

            displayVideos.forEach(videoData => {
                const item = listEl.querySelector(`.history-item[data-uid="${videoData.uid}"]`);
                if (item) {
                    const isActive = videoData.uid === currentUid;
                    item.classList.toggle('active-tab-video', isActive);
                    
                    // Re-order logic: Move the designated top video to the first position
                    if (videoData.uid === topVideoUid && item.previousElementSibling) {
                        listEl.prepend(item);
                    }

                    const timeEl = item.querySelector('.time-readout');
                    const percentEl = item.querySelector('.video-percent');
                    const progressBar = item.querySelector('.progress-bar-fill');
                    const percent = videoData.totalDuration > 0 ? Math.round((videoData.watchedDuration / videoData.totalDuration) * 100) : 0;
                    
                    const newTimeText = `${formatTime(Math.round(videoData.currentPosition || 0))} / ${formatTime(Math.round(videoData.totalDuration))}`;
                    if (timeEl && timeEl.textContent !== newTimeText) {
                        timeEl.textContent = newTimeText;
                    }

                    if (percentEl) {
                        const watchedTimeText = formatTime(Math.round(videoData.watchedDuration));
                        const watchedBadgeSpan = percentEl.closest('.watch-stats').querySelector('.watched-badge span');
                        if (watchedBadgeSpan && watchedBadgeSpan.textContent !== watchedTimeText) {
                            watchedBadgeSpan.textContent = watchedTimeText;
                        }

                        const percentText = `${percent}%`;
                        if (percentEl.textContent !== percentText) {
                            percentEl.textContent = percentText;
                        }
                    }

                    if (progressBar) {
                        const barPercent = videoData.totalDuration > 0 ? Math.min(100, ((videoData.currentPosition || 0) / videoData.totalDuration) * 100) : 0;
                        const newWidth = `${barPercent}%`;
                        if (progressBar.style.width !== newWidth) {
                            progressBar.style.width = newWidth;
                        }
                    }
                    const newPos = Math.floor(videoData.currentPosition || 0);
                    if (item.dataset.time !== String(newPos)) {
                        item.dataset.time = newPos;
                    }
                }
            });
        }
    } else if (activeView === 'channel-distribution') {
        if (activeView !== lastRenderedView || selectedDayFilter !== lastRenderedFilter) {
            lastRenderedView = activeView;
            lastRenderedFilter = selectedDayFilter;
            renderChannelDistribution(getFilteredAnalyticsData());
        }
    } else {
        if (activeView !== lastRenderedView || selectedDayFilter !== lastRenderedFilter) {
            lastRenderedView = activeView;
            lastRenderedFilter = selectedDayFilter;
            renderAnalyticsView();
        }
    }
}
function appendHistoryBatch() {
    const listEl = document.getElementById('video-history-list');
    const loadingEl = document.getElementById('history-loading');
    if (!listEl || isInfiniteScrolling || loadedVideoCount >= fullSortedVideos.length) {
        if (loadingEl) loadingEl.style.display = 'none';
        return;
    }

    if (loadingEl) loadingEl.style.display = 'flex';
    isInfiniteScrolling = true;

    // Small delay to allow the spinner to show up (even though local render is fast)
    setTimeout(() => {
        const batch = fullSortedVideos.slice(loadedVideoCount, loadedVideoCount + historyPageSize);
        const fragment = document.createDocumentFragment();
        
        batch.forEach(v => {
            const li = document.createElement('li');
            const percent = v.totalDuration > 0 ? Math.round((v.watchedDuration / v.totalDuration) * 100) : 0;
            const isActive = v.uid === currentUid;
            
            li.className = `history-item ${isActive ? 'active-tab-video' : ''}`;
            li.dataset.videoId = v.id;
            li.dataset.uid = v.uid;
            li.dataset.time = Math.floor(v.currentPosition || 0);
            
            li.innerHTML = `
                <img class="history-thumb" src="${v.thumbnail}" alt="thumbnail" onerror="this.onerror=null;this.src='https://www.gstatic.com/youtube/src/web/htdocs/img/favicon_144x144.png';">
                <div class="history-info">
                    <div class="video-header-row">
                        <div style="flex: 1; min-width: 0;">
                            <span class="video-title" title="${v.title}">${v.title}</span>
                            <span class="video-channel">${v.channelName || ''}</span>
                        </div>
                        <button class="delete-video-btn" title="Remove from History">${icons.delete}</button>
                    </div>
                    <div class="video-meta">
                        <span class="time-readout">${formatTime(Math.round(v.currentPosition || 0))} / ${formatTime(Math.round(v.totalDuration))}</span>
                        <div class="watch-stats">
                            <div class="watched-badge">
                                <span>${formatTime(Math.round(v.watchedDuration))}</span>
                            </div>
                            <span class="video-percent">${percent}%</span>
                        </div>
                    </div>
                    <div class="progress-bar-container">
                        <div class="progress-bar-fill" style="width: ${v.totalDuration > 0 ? Math.min(100, ((v.currentPosition || 0) / v.totalDuration) * 100) : 0}%"></div>
                    </div>
                </div>
            `;

            li.onclick = (e) => {
                e.stopPropagation();
                const vid = li.dataset.videoId;
                const t = li.dataset.time;
                if (vid && vid !== 'undefined') {
                    window.location.href = `https://www.youtube.com/watch?v=${vid}&t=${t}s`;
                }
            };

            const delBtn = li.querySelector('.delete-video-btn');
            if (delBtn) {
                delBtn.onclick = (e) => {
                    e.stopPropagation();
                    const uid = li.dataset.uid;
                    const videoTitle = li.querySelector('.video-title').textContent;

                    showConfirmModal({
                        title: 'Remove from History?',
                        message: `Are you sure you want to remove "${videoTitle}" from your watch history?`,
                        confirmText: 'Remove',
                        cancelText: 'Cancel',
                        icon: '🗑️',
                        onConfirm: () => {
                            deleteHistoryVideo(uid);
                            lastVideoCount = -1; // Force rebuild
                            renderStats();
                        }
                    });
                };
            }
            
            fragment.appendChild(li);
        });

        listEl.appendChild(fragment);
        loadedVideoCount += batch.length;
        isInfiniteScrolling = false;
        
        // Hide loading indicator if no more videos
        if (loadedVideoCount >= fullSortedVideos.length && loadingEl) {
            loadingEl.style.display = 'none';
        }
    }, 100);
}


// ─── stats-tracker/analytics-render.js ─────────────────────────── 
// === Analytics Rendering: Bar chart, pie chart, heatmaps, insights ===

let selectedHeatmapYear = 'Last 365 Days';

function renderAnalyticsView() {
    const data = getFilteredAnalyticsData();
    
    // Update Overview Stats
    updateAnalyticsOverview(data);
    
    // Render Components
    renderMainTrendsChart(data);
    renderWatchDistribution(data);
    renderActivityHeatmap();
    renderDetailedInsights(data);
}

/**
 * Aggregates watch data based on the current global selectedDayFilter
 */
function getFilteredAnalyticsData() {
    const now = new Date();
    const result = {
        days: [], // { key, label, value, color }
        channels: [], // { label, value }
        totalWatchTime: 0,
        videoCounts: 0,
        averageWatchTime: 0,
        maxDay: { key: '', value: 0 }
    };

    const channelsMap = {};

    let keysToInclude = [];

    if (selectedDayFilter === 'today') {
        keysToInclude = [getDayKey(now)];
    } else if (selectedDayFilter === 'yesterday') {
        const yest = new Date(now);
        yest.setDate(yest.getDate() - 1);
        keysToInclude = [getDayKey(yest)];
    } else if (selectedDayFilter.endsWith('days')) {
        const daysCount = parseInt(selectedDayFilter);
        for (let i = daysCount - 1; i >= 0; i--) {
            const d = new Date(now);
            d.setDate(d.getDate() - i);
            keysToInclude.push(getDayKey(d));
        }
    } else if (selectedDayFilter === 'all') {
        keysToInclude = Object.keys(allHistory).sort();
    } else {
        // Specific date YYYY-MM-DD
        keysToInclude = [selectedDayFilter];
    }

    keysToInclude.forEach((key, index) => {
        const dayData = allHistory[key] || { watchTime: 0, activeTime: 0, videos: [] };
        const val = dayData.watchTime;
        
        // Always show labels, but format shorter for larger ranges
        const [y, m, d] = key.split('-');
        const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
        let label = '';
        
        if (keysToInclude.length <= 14) {
             label = `${d} ${months[parseInt(m)-1]}`;
        } else {
             label = `${d}/${m}`;
        }

        result.days.push({
            key,
            label,
            value: val,
            color: dayColors[index % dayColors.length],
            activeTime: dayData.activeTime || 0,
            videoCount: dayData.videos ? dayData.videos.length : 0,
            topVideos: [...(dayData.videos || [])]
                .sort((a, b) => (b.watchedDuration || 0) - (a.watchedDuration || 0))
                .slice(0, 3)
                .map(v => v.title)
        });

        // Aggregate Channels
        (dayData.videos || []).forEach(v => {
            const chan = v.channelName || 'Unknown Channel';
            const duration = (v.watchedDuration || 0);
            
            if (!channelsMap[chan]) {
                channelsMap[chan] = { 
                    value: 0, 
                    thumbnail: v.thumbnail, 
                    videos: new Map(), // Use Map to track duration per unique video
                    topVideo: { title: v.title, duration: duration }
                };
            }
            
            channelsMap[chan].value += duration;
            
            // Track duration for this specific video ID to find top video
            const vidId = v.id || v.uid;
            const existingVidData = channelsMap[chan].videos.get(vidId) || { duration: 0, title: v.title };
            existingVidData.duration += duration;
            channelsMap[chan].videos.set(vidId, existingVidData);
            
            // Update Top Video if this overall duration is higher
            if (existingVidData.duration > channelsMap[chan].topVideo.duration) {
                channelsMap[chan].topVideo = { title: existingVidData.title, duration: existingVidData.duration };
            }
            
            // Prioritize Captured Channel Logo > Captured Video Thumbnail > Generated Fallback
            const thumbFallback = `https://i.ytimg.com/vi/${vidId}/default.jpg`;
            const logo = v.channelThumb || v.thumbnail || thumbFallback;
            
            // Only update if we don't have a logo yet, or if we have a real channelThumb now
            const isRealLogo = v.channelThumb && !v.channelThumb.startsWith('data:');
            if (!channelsMap[chan].thumbnail || isRealLogo) {
                channelsMap[chan].thumbnail = logo;
            }
        });

        result.totalWatchTime += val;
        result.videoCounts += (dayData.videos ? dayData.videos.length : 0);
        
        if (val > result.maxDay.value) {
            result.maxDay = { key, value: val };
        }
    });

    result.averageWatchTime = keysToInclude.length > 0 ? result.totalWatchTime / keysToInclude.length : 0;
    
    // Sort and finalize channels
    result.channels = Object.entries(channelsMap)
        .map(([label, info]) => ({ 
            label, 
            value: info.value,
            videoCount: info.videos.size,
            thumbnail: info.thumbnail,
            topVideo: info.topVideo.title,
            avgTime: info.value / info.videos.size
        }))
        .sort((a, b) => b.value - a.value);
    
    return result;
}

function updateAnalyticsOverview(data) {
    const totalEl = document.getElementById('analytics-total-time');
    const avgEl = document.getElementById('analytics-avg-time');
    const periodEl = document.getElementById('trends-period-label');

    if (totalEl) totalEl.textContent = formatTimeShort(data.totalWatchTime);
    if (avgEl) avgEl.textContent = formatTimeShort(data.averageWatchTime);
    
    if (periodEl) {
        if (selectedDayFilter === 'today') periodEl.textContent = 'Today';
        else if (selectedDayFilter === 'yesterday') periodEl.textContent = 'Yesterday';
        else if (selectedDayFilter.endsWith('days')) periodEl.textContent = `Last ${parseInt(selectedDayFilter)} Days`;
        else if (selectedDayFilter === 'all') periodEl.textContent = 'All Time';
        else periodEl.textContent = selectedDayFilter;
    }
}

function formatTimeShort(seconds) {
    if (seconds < 60) return `${Math.round(seconds)}s`;
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    return h > 0 ? `${h}h ${m}m` : `${m}m`;
}

function renderMainTrendsChart(data) {
    const chartContainer = document.getElementById('stats-chart');
    if (!chartContainer) return;

    if (data.days.length === 0) {
        chartContainer.innerHTML = '<div class="no-data-msg">No data for this period</div>';
        return;
    }

    const maxValue = Math.max(...data.days.map(d => d.value), 3600); // at least 1hr scale
    
    chartContainer.innerHTML = data.days.map(d => {
        const height = Math.max(4, (d.value / maxValue) * 100);
        const isActive = d.key === getDayKey(new Date());
        
        // Construct Rich Tooltip HTML
        const [y, m, day] = d.key.split('-');
        const dateObj = new Date(y, m-1, day);
        const dateStr = dateObj.toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' });
        
        let tooltipContent = `
            <div class="tooltip-date">${dateStr}</div>
            <div class="tooltip-stat-row">
                <span class="tooltip-stat-label">Watch Time</span>
                <span class="tooltip-stat-value">${formatTime(Math.round(d.value))}</span>
            </div>
        `;
        
        if (d.activeTime > 0) {
            tooltipContent += `
                <div class="tooltip-stat-row">
                    <span class="tooltip-stat-label">Active Time</span>
                    <span class="tooltip-stat-value">${formatTime(Math.round(d.activeTime))}</span>
                </div>
            `;
        }
        
        tooltipContent += `
            <div class="tooltip-stat-row">
                <span class="tooltip-stat-label">Videos</span>
                <span class="tooltip-stat-value">${d.videoCount}</span>
            </div>
        `;
        
        if (d.topVideos && d.topVideos.length > 0) {
            tooltipContent += `
                <div class="tooltip-videos-header">Top Videos</div>
                ${d.topVideos.map(title => `<div class="tooltip-video-item">${title}</div>`).join('')}
            `;
        }

        return `
            <div class="chart-bar-wrapper ${isActive ? 'active' : ''}" data-tooltip='${tooltipContent.replace(/'/g, "&apos;")}'>
                <div class="chart-bar-outer">
                    <div class="chart-bar-fill" style="height: ${height}%; background: ${d.color}"></div>
                </div>
                ${d.label ? `<span class="chart-label">${d.label}</span>` : ''}
            </div>
        `;
    }).join('');

    // Re-bind tooltips
    bindAnalyticsTooltips(chartContainer);

    // Setup scroll arrows
    initCustomScroll('chart-scroll-track', 'chart-scroll-left', 'chart-scroll-right');
}

function initCustomScroll(trackId, leftId, rightId) {
    const track = document.getElementById(trackId);
    const leftArrow = document.getElementById(leftId);
    const rightArrow = document.getElementById(rightId);
    if (!track || !leftArrow || !rightArrow) return;

    // Auto-scroll to end on render
    track.scrollLeft = track.scrollWidth;

    let scrollInterval = null;
    let currentSpeed = 3;
    const baseSpeed = 3;
    const turboSpeed = 12;

    const startScroll = (direction) => {
        stopScroll();
        scrollInterval = setInterval(() => {
            track.scrollLeft += direction * currentSpeed;
        }, 16); // ~60fps
    };

    const stopScroll = () => {
        if (scrollInterval) {
            clearInterval(scrollInterval);
            scrollInterval = null;
        }
        currentSpeed = baseSpeed;
    };

    const enhanceSpeed = () => {
        currentSpeed = turboSpeed;
    };

    leftArrow.onmouseenter = () => startScroll(-1);
    leftArrow.onmouseleave = stopScroll;
    leftArrow.onmousedown = (e) => {
        if (e.button === 0) enhanceSpeed();
    };
    leftArrow.onmouseup = () => currentSpeed = baseSpeed;

    rightArrow.onmouseenter = () => startScroll(1);
    rightArrow.onmouseleave = stopScroll;
    rightArrow.onmousedown = (e) => {
        if (e.button === 0) enhanceSpeed();
    };
    rightArrow.onmouseup = () => currentSpeed = baseSpeed;

    // Update arrow visibility based on scroll position  
    const updateArrowVisibility = () => {
        const atStart = track.scrollLeft <= 2;
        const atEnd = track.scrollLeft + track.clientWidth >= track.scrollWidth - 2;
        leftArrow.style.opacity = atStart ? '0.15' : '';
        rightArrow.style.opacity = atEnd ? '0.15' : '';
        leftArrow.style.pointerEvents = atStart ? 'none' : '';
        rightArrow.style.pointerEvents = atEnd ? 'none' : '';
    };

    track.onscroll = updateArrowVisibility;
    // Initial check after render settles
    setTimeout(updateArrowVisibility, 50);
}

function renderWatchDistribution(data) {
    const pieChart = document.getElementById('pie-chart');
    const pieLegend = document.getElementById('pie-legend');
    const centerVal = document.getElementById('pie-total-value');
    if (!pieChart || !pieLegend) return;

    if (centerVal) centerVal.textContent = formatTimeShort(data.totalWatchTime);

    if (data.totalWatchTime === 0 || data.channels.length === 0) {
        pieChart.style.background = 'var(--stats-chart-bar-bg)';
        pieLegend.innerHTML = '<div class="legend-empty">No activity recorded</div>';
        return;
    }

    // Calculate slices for ALL channels (per user request)
    const sorted = [...data.channels];
    let cumulativePercent = 0;
    const slices = sorted.map((c, i) => {
        const start = cumulativePercent;
        const end = start + (c.value / data.totalWatchTime) * 100;
        cumulativePercent = end;
        return { 
            ...c, 
            start, 
            end,
            color: dayColors[i % dayColors.length]
        };
    });

    const updatePieHighlight = (hoverIdx) => {
        const gradient = slices.map((s, i) => {
            let color = s.color;
            if (hoverIdx !== -1 && i !== hoverIdx) {
                // Dim other slices using a simple rgba opacity if they were hex
                // Since they are strings, we'll convert them or just use a dimmed overlay logic.
                // For simplicity, we'll use a helper to dim the hex colors.
                color = hexToRgba(color, 0.2);
            }
            return `${color} ${s.start}% ${s.end}%`;
        }).join(', ');
        pieChart.style.background = `conic-gradient(${gradient})`;
    };

    // Helper to dim hex colors
    function hexToRgba(hex, alpha) {
        let r, g, b;
        if (hex.length === 4) {
            r = parseInt(hex[1] + hex[1], 16);
            g = parseInt(hex[2] + hex[2], 16);
            b = parseInt(hex[3] + hex[3], 16);
        } else {
            r = parseInt(hex.slice(1, 3), 16);
            g = parseInt(hex.slice(3, 5), 16);
            b = parseInt(hex.slice(5, 7), 16);
        }
        return `rgba(${r}, ${g}, ${b}, ${alpha})`;
    }

    pieChart.style.background = `conic-gradient(${slices.map(s => `${s.color} ${s.start}% ${s.end}%`).join(', ')})`;
    
    // Render Top 5 as pills + View All button
    pieLegend.innerHTML = slices.slice(0, 5).map(d => `
        <div class="legend-item" data-channel="${d.label || d.key}">
            <span class="legend-color" style="background: ${d.color}"></span>
            <span class="legend-label">${d.label || d.key}</span>
            <span class="legend-value">${Math.round((d.value/data.totalWatchTime)*100)}%</span>
        </div>
    `).join('') + `
        <button id="view-all-channels" class="view-more-btn">
            View All Channels
        </button>
    `;

    // Setup "View All Channels" view switching
    const viewAllBtn = document.getElementById('view-all-channels');
    if (viewAllBtn) {
        viewAllBtn.onclick = (e) => {
            if (e) e.stopPropagation();
            activeView = 'channel-distribution';
            localStorage.setItem('ytt_active_view', activeView);
            switchView(activeView);
            renderChannelDistribution(data);
        };
    }


    // Interaction for legend items
    pieLegend.querySelectorAll('.legend-item').forEach((item, idx) => {
        item.onmouseenter = () => updatePieHighlight(idx);
        item.onmouseleave = () => updatePieHighlight(-1);
    });

    // Interaction
    const tooltip = document.getElementById('stats-tooltip');
    pieChart.onmousemove = (e) => {
        const rect = pieChart.getBoundingClientRect();
        const centerX = rect.left + rect.width / 2;
        const centerY = rect.top + rect.height / 2;
        let angle = Math.atan2(e.clientY - centerY, e.clientX - centerX) * (180 / Math.PI) + 90;
        if (angle < 0) angle += 360;
        const percent = (angle / 360) * 100;
        
        const activeSlice = slices.find(s => percent >= s.start && percent < s.end);
        if (activeSlice) {
            const pct = Math.round((activeSlice.value / data.totalWatchTime) * 100);
            const avgStr = formatTimeShort(activeSlice.avgTime || (activeSlice.value / activeSlice.videoCount));
            tooltip.innerHTML = `
                <div class="tooltip-date">${activeSlice.label || activeSlice.key}</div>
                <div class="tooltip-stat-row">
                    <span class="tooltip-stat-label">Watch Time</span>
                    <span class="tooltip-stat-value">${formatTime(Math.round(activeSlice.value))}</span>
                </div>
                <div class="tooltip-stat-row">
                    <span class="tooltip-stat-label">Share</span>
                    <span class="tooltip-stat-value">${pct}%</span>
                </div>
                <div class="tooltip-stat-row">
                    <span class="tooltip-stat-label">Videos</span>
                    <span class="tooltip-stat-value">${activeSlice.videoCount}</span>
                </div>
                <div class="tooltip-stat-row">
                    <span class="tooltip-stat-label">Avg / Video</span>
                    <span class="tooltip-stat-value">${avgStr}</span>
                </div>
                ${activeSlice.topVideo ? `
                    <div class="tooltip-videos-header">Most Watched</div>
                    <div class="tooltip-video-item">${activeSlice.topVideo}</div>
                ` : ''}
            `;
            tooltip.classList.add('visible');
            positionTooltip(e, tooltip);
            // Highlight the hovered slice
            const sliceIdx = slices.indexOf(activeSlice);
            updatePieHighlight(sliceIdx);
        } else {
            tooltip.classList.remove('visible');
            updatePieHighlight(-1);
        }
    };
    pieChart.onmouseleave = () => {
        tooltip.classList.remove('visible');
        updatePieHighlight(-1);
    };
}

function renderChannelDistribution(data) {
    const listEl = document.getElementById('full-channel-list');
    if (!listEl) return;

    if (!data || !data.channels || data.channels.length === 0) {
        listEl.innerHTML = '<div class="loading-placeholder">No channel data available</div>';
        return;
    }

    // Sort all channels by value descending
    const sorted = [...data.channels].sort((a, b) => b.value - a.value);
    
    listEl.innerHTML = sorted.map((c, index) => {
        const percent = Math.round((c.value / data.totalWatchTime) * 100);
        const rank = index + 1;
        const avgStr = formatTimeShort(c.avgTime || (c.value / c.videoCount));
        
        return `
            <div class="channel-card-detailed">
                <div class="channel-rank-badge ${rank <= 3 ? 'top-rank' : ''}">${rank}</div>
                <div class="channel-info-detailed">
                    <div class="channel-main-row">
                        <span class="channel-name" title="${c.label || c.key}">${c.label || c.key}</span>
                        <div class="channel-percent-detailed">${percent}%</div>
                    </div>
                    <div class="channel-stats-row">
                        <span>${formatTime(Math.round(c.value))} total • ${c.videoCount} video${c.videoCount !== 1 ? 's' : ''} • Avg ${avgStr}/vid</span>
                    </div>
                    <div class="channel-top-video-row">
                        <span class="top-video-title" title="${c.topVideo}">🏆 ${c.topVideo}</span>
                    </div>
                    <div class="channel-progress-container">
                        <div class="channel-progress-fill" style="width: ${percent}%"></div>
                    </div>
                </div>
            </div>
        `;
    }).join('');
}

function renderActivityHeatmap() {
    const container = document.getElementById('activity-heatmap');
    const selectorContainer = document.getElementById('heatmap-year-selector');
    if (!container) return;

    // 1. Year Discovery & Selector Rendering
    const years = Array.from(new Set(Object.keys(allHistory).map(k => k.split('-')[0]))).sort((a, b) => b - a);
    const options = ['Last 365 Days', ...years];
    
    if (selectorContainer) {
        selectorContainer.innerHTML = `
            <div class="custom-dropdown heatmap-year-dropdown" id="heatmap-year-dropdown">
                <div class="dropdown-trigger">
                    <span>${selectedHeatmapYear}</span>
                    <svg class="dropdown-chevron" width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="6 9 12 15 18 9"></polyline></svg>
                </div>
                <div class="dropdown-menu">
                    ${options.map(y => `
                        <div class="dropdown-item ${selectedHeatmapYear == y ? 'active' : ''}" data-value="${y}">
                            ${y}
                        </div>
                    `).join('')}
                </div>
            </div>
        `;
        
        const dropdown = document.getElementById('heatmap-year-dropdown');
        if (dropdown) {
            const trigger = dropdown.querySelector('.dropdown-trigger');
            trigger.onclick = (e) => {
                e.stopPropagation();
                // Close other open dropdowns first
                document.querySelectorAll('.custom-dropdown.open').forEach(d => {
                    if (d !== dropdown) d.classList.remove('open');
                });
                dropdown.classList.toggle('open');
            };

            dropdown.querySelectorAll('.dropdown-item').forEach(item => {
                item.onclick = (e) => {
                    e.stopPropagation();
                    selectedHeatmapYear = item.dataset.value;
                    dropdown.classList.remove('open');
                    renderActivityHeatmap();
                };
            });
        }
    }

    // 2. Date Range Calculation
    let startDate, endDate, weeks;
    const now = new Date();
    const monthNames = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
    const days = ['', 'Mon', '', 'Wed', '', 'Fri', ''];

    if (selectedHeatmapYear === 'Last 365 Days') {
        weeks = 53; // Full year sliding window
        endDate = new Date(now);
        startDate = new Date(now);
        startDate.setDate(now.getDate() - (weeks * 7) + 1);
        // Align to Sunday
        while (startDate.getDay() !== 0) {
            startDate.setDate(startDate.getDate() - 1);
        }
    } else {
        const year = parseInt(selectedHeatmapYear);
        startDate = new Date(year, 0, 1);
        endDate = new Date(year, 11, 31);
        // Align start to the first Sunday on or before Jan 1
        while (startDate.getDay() !== 0) {
            startDate.setDate(startDate.getDate() - 1);
        }
        // Calculate weeks needed to cover the whole year
        const diffTime = Math.abs(endDate - startDate);
        weeks = Math.ceil(diffTime / (1000 * 60 * 60 * 24 * 7));
    }
    
    let heatmapData = [];
    let months = [];
    let lastMonth = -1;

    for (let i = 0; i < weeks * 7; i++) {
        const d = new Date(startDate);
        d.setDate(startDate.getDate() + i);
        const key = getDayKey(d);
        const dayData = allHistory[key] || { watchTime: 0, activeTime: 0, videos: [] };
        const val = dayData.watchTime;
        
        // Month label logic
        if (i % 7 === 0) {
            const m = d.getMonth();
            if (m !== lastMonth) {
                months.push({ name: monthNames[m], index: i / 7 });
                lastMonth = m;
            }
        }

        let level = 0;
        if (val > 0) level = 1;
        if (val > 3600) level = 2;
        if (val > 7200) level = 3;
        if (val > 14400) level = 4;

        const dateStr = d.toLocaleDateString(undefined, { weekday: 'short', month: 'short', day: 'numeric', year: 'numeric' });
        const videos = [...(dayData.videos || [])]
            .sort((a, b) => (b.watchedDuration || 0) - (a.watchedDuration || 0))
            .slice(0, 3);
            
        let tooltipHtml = `
            <div class="tooltip-date">${dateStr}</div>
            <div class="tooltip-stat-row">
                <span class="tooltip-stat-label">Watch Time</span>
                <span class="tooltip-stat-value">${formatTime(Math.round(val))}</span>
            </div>
            <div class="tooltip-stat-row">
                <span class="tooltip-stat-label">Videos</span>
                <span class="tooltip-stat-value">${dayData.videos ? dayData.videos.length : 0}</span>
            </div>
        `;
        
        if (videos.length > 0) {
            tooltipHtml += `<div class="tooltip-videos-header">Top Videos:</div>`;
            videos.forEach(v => {
                tooltipHtml += `<div class="tooltip-video-item">${v.title}</div>`;
            });
        }

        heatmapData.push({ key, val, level, tooltipHtml });
    }

    let html = `
        <div class="heatmap-modern-wrapper">
            <div class="heatmap-months-row" style="grid-template-columns: repeat(${weeks}, 11px)">
                ${months.map((m, i) => `
                    <span class="month-label" style="grid-column: ${m.index + 1}">${m.name}</span>
                `).join('')}
            </div>
            <div class="heatmap-main-row">
                <div class="heatmap-days-col">
                    ${days.map(d => `<span class="day-label">${d}</span>`).join('')}
                </div>
                <div class="heatmap-grid modern" style="grid-template-columns: repeat(${weeks}, 11px)">
                    ${heatmapData.map(d => `
                        <div class="heatmap-cell level-${d.level}" data-tooltip="${d.tooltipHtml.replace(/"/g, '&quot;')}"></div>
                    `).join('')}
                </div>
            </div>
        </div>
    `;
    
    container.innerHTML = html;
    bindAnalyticsTooltips(container);

    initCustomScroll('activity-heatmap', 'heatmap-scroll-left', 'heatmap-scroll-right');
}

function renderDetailedInsights(data) {
    const insightEl = document.getElementById('key-insights');
    if (!insightEl) return;

    const insights = [];

    // insight 1: Peak Activity
    if (data.maxDay.value > 0) {
        insights.push({
            icon: '🔥',
            title: 'Peak Activity',
            text: `Your highest watch time was on <strong>${data.maxDay.key}</strong> with <strong>${formatTime(Math.round(data.maxDay.value))}</strong>.`
        });
    }

    // insight 2: Consistency
    const activeDays = data.days.filter(d => d.value > 0).length;
    const consistency = Math.round((activeDays / data.days.length) * 100);
    insights.push({
        icon: '🎯',
        title: 'Consistency',
        text: `You watched YouTube on <strong>${activeDays}</strong> out of the last <strong>${data.days.length}</strong> days (${consistency}%).`
    });

    // insight 3: Binge-watching check
    const bingeDays = data.days.filter(d => d.value > 10800).length; // 3 hours
    if (bingeDays > 0) {
        insights.push({
            icon: '⚠️',
            title: 'Binge Warning',
            text: `You had <strong>${bingeDays}</strong> sessions exceeding 3 hours. Consider taking more frequent breaks!`
        });
    }

    insightEl.innerHTML = insights.map(i => `
        <div class="insight-card-modern">
            <div class="insight-header-row">
                <span class="insight-icon-vibrant">${i.icon}</span>
                <h4>${i.title}</h4>
            </div>
            <p>${i.text}</p>
        </div>
    `).join('');
}

function bindAnalyticsTooltips(container) {
    const tooltip = document.getElementById('stats-tooltip');
    container.querySelectorAll('[data-tooltip]').forEach(el => {
        el.onmouseenter = (e) => {
            tooltip.innerHTML = el.dataset.tooltip;
            tooltip.classList.add('visible');
            positionTooltip(e, tooltip);
        };
        el.onmousemove = (e) => positionTooltip(e, tooltip);
        el.onmouseleave = () => tooltip.classList.remove('visible');
    });
}

function positionTooltip(e, tooltip) {
    const margin = 15;
    const tooltipWidth = tooltip.offsetWidth;
    const tooltipHeight = tooltip.offsetHeight;
    let left = e.clientX + margin;
    let top = e.clientY - margin;
    if (left + tooltipWidth > window.innerWidth) left = e.clientX - tooltipWidth - margin;
    if (top < margin) top = margin;
    if (top + tooltipHeight > window.innerHeight - margin) top = window.innerHeight - tooltipHeight - margin;
    tooltip.style.left = left + 'px';
    tooltip.style.top = top + 'px';
}


// ─── break-reminder/reminder.js ────────────────────────────────── 
// === Break Reminder: Quote fetching, modal, and timer ===

async function fetchZenQuote() {
    return new Promise((resolve) => {
        safeSendMessage({ action: 'FETCH_QUOTE' }, (response) => {
            if (response && response.text) {
                resolve(response);
            } else {
                // Randomized local fallbacks if message fails
                const fallbacks = [
                    { text: "The secret of getting ahead is getting started.", author: "Mark Twain" },
                    { text: "It does not matter how slowly you go as long as you do not stop.", author: "Confucius" },
                    { text: "Everything you've ever wanted is on the other side of fear.", author: "George Addair" }
                ];
                resolve(fallbacks[Math.floor(Math.random() * fallbacks.length)]);
            }
        });
    });
}

function showBreakModal(quote) {
    if (document.getElementById('break-reminder-modal')) return;
    
    // Default fallback if quote failed
    const finalQuote = quote || { text: "The secret of getting ahead is getting started.", author: "Mark Twain" };
    
    const overlay = document.createElement('div');
    overlay.id = 'break-reminder-modal';
    overlay.className = 'break-modal-overlay';
    // Accessibility: Role and Aria
    overlay.setAttribute('role', 'dialog');
    overlay.setAttribute('aria-modal', 'true');
    overlay.setAttribute('aria-labelledby', 'break-modal-title');
    
    overlay.innerHTML = `
        <div class="break-modal">
            <div class="modal-drag-handle"></div>
            <div class="break-modal-icon">☕</div>
            <h2 id="break-modal-title" class="break-modal-title">Time for a Break!</h2>
            <p class="break-modal-subtitle">You've been watching for ${breakSettings.intervalMinutes} minutes straight.</p>
            <blockquote class="break-modal-quote">
                <p>"${finalQuote.text}"</p>
                <cite>— ${finalQuote.author}</cite>
            </blockquote>
            <div class="break-modal-actions">
                <button id="break-keep-watching" class="break-btn secondary">Keep Watching</button>
                <button id="break-go-work" class="break-btn primary">Go to Work</button>
            </div>
        </div>
    `;
    document.body.appendChild(overlay);
    
    // Prevent background scroll and selection
    document.body.style.overflow = 'hidden';
    document.body.style.userSelect = 'none';
    
    const modal = overlay.querySelector('.break-modal');
    const keepWatchingBtn = document.getElementById('break-keep-watching');
    const goWorkBtn = document.getElementById('break-go-work');
    
    // Focus the first action button
    setTimeout(() => keepWatchingBtn.focus(), 100);
    
    // Animate in
    requestAnimationFrame(() => overlay.classList.add('visible'));

    // Swipe to Dismiss (Mobile)
    let touchStartY = 0;
    let currentY = 0;
    let isSwiping = false;

    modal.addEventListener('touchstart', (e) => {
        if (window.innerWidth > 600) return;
        touchStartY = e.touches[0].clientY;
        modal.style.transition = 'none';
        isSwiping = true;
    }, { passive: true });

    modal.addEventListener('touchmove', (e) => {
        if (!isSwiping) return;
        currentY = e.touches[0].clientY;
        const deltaY = currentY - touchStartY;
        
        if (deltaY > 0) { // Only allow swiping down
            modal.style.transform = `translateY(${deltaY}px)`;
        }
    }, { passive: true });

    modal.addEventListener('touchend', () => {
        if (!isSwiping) return;
        isSwiping = false;
        modal.style.transition = 'transform 0.3s cubic-bezier(0.16, 1, 0.3, 1)';
        
        const deltaY = currentY - touchStartY;
        if (deltaY > 120) {
            // Dismiss
            dismissModal();
        } else {
            // Snap back
            modal.style.transform = 'translateY(0)';
        }
    });

    const dismissModal = () => {
        overlay.classList.remove('visible');
        document.body.style.overflow = ''; // Restore scroll
        document.body.style.userSelect = ''; // Restore selection
        
        if (window.innerWidth <= 600) {
            modal.style.transform = 'translateY(100%)';
        }
        setTimeout(() => overlay.remove(), 400);
        continuousWatchStart = Date.now(); // Reset timer
        breakModalShown = false;
        preFetchedQuote = null; // Clear pre-fetched for next cycle
        
        // Resume video playback
        const video = document.querySelector('video');
        if (video) video.play();
    };
    
    // Accessibility: Click outside to close
    overlay.onclick = (e) => {
        if (e.target === overlay) {
            dismissModal();
        }
    };

    // Accessibility: Focus Trap (Tab behavior)
    overlay.onkeydown = (e) => {
        if (e.key === 'Tab') {
            const focusables = [keepWatchingBtn, goWorkBtn];
            const first = focusables[0];
            const last = focusables[focusables.length - 1];
            
            if (e.shiftKey) { // Shift + Tab
                if (document.activeElement === first) {
                    last.focus();
                    e.preventDefault();
                }
            } else { // Tab
                if (document.activeElement === last) {
                    first.focus();
                    e.preventDefault();
                }
            }
        }
        if (e.key === 'Escape') {
            dismissModal();
        }
    };
    
    if (keepWatchingBtn) {
        keepWatchingBtn.onclick = (e) => {
            e.stopPropagation();
            dismissModal();
        };
    }

    if (goWorkBtn) {
        goWorkBtn.onclick = () => {
            window.location.href = breakSettings.workUrl || 'https://www.google.com';
        };
    }
}

function updateTimerBadge(remainingMinutes) {
    const badge = document.getElementById('stats-timer-badge');
    if (!badge) return;

    if (!breakSettings.enabled || remainingMinutes <= 0 || breakModalShown) {
        badge.style.display = 'none';
        return;
    }

    badge.style.display = 'block';
    
    if (remainingMinutes < 1) {
        const seconds = Math.ceil(remainingMinutes * 60);
        badge.textContent = `${seconds}s`;
        badge.style.background = '#FF0033'; // High urgency
    } else {
        badge.textContent = `${Math.ceil(remainingMinutes)}m`;
        badge.style.background = '#0f0f0f';
    }
}


function checkBreakReminder() {
    if (!breakSettings.enabled) {
        updateTimerBadge(0);
        return;
    }
    
    const video = document.querySelector('video');
    if (!video || video.paused) {
        continuousWatchStart = null;
        breakModalShown = false;
        updateTimerBadge(0);
        return;
    }
    
    if (!continuousWatchStart) {
        continuousWatchStart = Date.now();
        return;
    }
    
    const elapsed = (Date.now() - continuousWatchStart) / 1000 / 60; // minutes
    
    // Pre-fetch quote 5 seconds before the interval (5/60 minutes)
    const preFetchThreshold = breakSettings.intervalMinutes - (5 / 60);
    if (elapsed >= preFetchThreshold && !preFetchedQuote && !isFetchingQuote) {
        isFetchingQuote = true;
        fetchZenQuote().then(quote => {
            preFetchedQuote = quote;
            isFetchingQuote = false;
        });
    }

    if (elapsed >= breakSettings.intervalMinutes && !breakModalShown) {
        breakModalShown = true;
        video.pause();
        showBreakModal(preFetchedQuote);
        updateTimerBadge(0);
    } else {
        updateTimerBadge(breakSettings.intervalMinutes - elapsed);
    }
}


// ─── dislike-counter/dislike-counter.js ────────────────────────── 
// === Dislike Counter: Fetches and displays dislike counts on YouTube videos ===

let lastDislikeVideoId = "";
let dislikeFetchInProgress = false;
let lastFetchedDislikeData = null;

function getVideoId() {
  const watchFlexy = document.querySelector("ytd-watch-flexy");
  if (watchFlexy && watchFlexy.getAttribute("video-id")) {
    return watchFlexy.getAttribute("video-id");
  }

  // Fallback to URL search params
  const urlParams = new URLSearchParams(window.location.search);
  const v = urlParams.get("v");
  if (v) return v;

  // Fallback for Shorts
  const pathParts = window.location.pathname.split("/");
  if (pathParts[1] === "shorts") return pathParts[2];

  return null;
}

function applyDislikeCountState(force = false) {
  if (dislikeCountSettings.enabled) {
    if (force) console.log("YTT: Force applying dislike state...");
    injectDislikeCount(force);
  } else {
    removeDislikeCount();
  }
}

function removeDislikeCount() {
  const el = document.getElementById("ytt-dislike-count");
  if (el) {
    console.log("YTT: Removing dislike count element.");
    el.remove();
  }

  // Reset button styles to YouTube defaults
  const dislikeBtn = document.querySelector(
    "dislike-button-view-model button, #segmented-dislike-button button, ytd-toggle-button-renderer.style-scope.ytd-menu-renderer:nth-child(2) button",
  );
  if (dislikeBtn) {
    dislikeBtn.style.removeProperty("width");
    dislikeBtn.style.removeProperty("min-width");
    dislikeBtn.style.removeProperty("padding-right");
    dislikeBtn.style.removeProperty("display");
    dislikeBtn.style.removeProperty("align-items");

    const parentVM = dislikeBtn.closest(
      "dislike-button-view-model, #segmented-dislike-button",
    );
    if (parentVM) {
      parentVM.style.removeProperty("width");
      parentVM.style.removeProperty("min-width");
    }
  }
  // Reset fetch state so re-enabling always triggers a fresh fetch
  lastDislikeVideoId = "";
  lastFetchedDislikeData = null;
  dislikeFetchInProgress = false;
}

function formatDislikeCount(count) {
  if (count >= 1000000) {
    const val = count / 1000000;
    return (val % 1 === 0 ? val.toFixed(0) : val.toFixed(1)) + "m";
  }
  if (count >= 1000) {
    const val = count / 1000;
    return (val % 1 === 0 ? val.toFixed(0) : val.toFixed(1)) + "k";
  }
  return count.toString();
}

async function fetchDislikeCount(videoId) {
  console.log(`YTT: Fetching dislike count for ${videoId}...`);
  try {
    const response = await fetch(
      `https://returnyoutubedislikeapi.com/votes?videoId=${videoId}`,
    );
    if (!response.ok) {
      console.error(`YTT: API Error: ${response.status}`);
      return null;
    }
    const data = await response.json();
    console.log("YTT: Dislike data received:", data.dislikes);
    return data;
  } catch (e) {
    console.error("YTT: Dislike fetch failed:", e);
    return null;
  }
}

function renderDislikeCount(data) {
  if (!dislikeCountSettings.enabled) return;
  if (!data || data.dislikes === undefined) return;

  // Re-query buttons to ensure they're current in the DOM
  const likeBtn = document.querySelector(
    "like-button-view-model button, #segmented-like-button button, ytd-toggle-button-renderer.style-scope.ytd-menu-renderer:nth-child(1) button",
  );
  const dislikeBtn = document.querySelector(
    "dislike-button-view-model button, #segmented-dislike-button button, ytd-toggle-button-renderer.style-scope.ytd-menu-renderer:nth-child(2) button",
  );

  if (!dislikeBtn) {
    return;
  }

  let countEl = document.getElementById("ytt-dislike-count");
  const countText = formatDislikeCount(data.dislikes);

  if (countEl) {
    if (countEl.textContent === countText) return;
    countEl.textContent = countText;
  } else {
    countEl = document.createElement("span");
    countEl.id = "ytt-dislike-count";
    countEl.textContent = countText;

    if (likeBtn) {
      const likeText = likeBtn.querySelector(
        ".yt-spec-button-shape-next__button-text-content, .yt-core-attributed-string",
      );
      if (likeText && likeText.textContent !== "") {
        const style = window.getComputedStyle(likeText);
        countEl.style.fontSize = style.fontSize;
        countEl.style.fontWeight = style.fontWeight;
        countEl.style.color = style.color;
        countEl.style.fontFamily = style.fontFamily;
      } else {
        countEl.style.fontSize = "14px";
        countEl.style.fontWeight = "500";
        countEl.style.color = "var(--yt-spec-text-primary)";
      }
    } else {
      countEl.style.fontSize = "14px";
      countEl.style.fontWeight = "500";
      countEl.style.color = "var(--yt-spec-text-primary)";
    }

    countEl.style.marginLeft = "8px";
    countEl.style.marginRight = "8px";
    countEl.style.display = "inline-block";
    countEl.style.verticalAlign = "middle";

    const icon = dislikeBtn.querySelector(
      ".yt-spec-button-shape-next__icon, yt-icon, .icon",
    );
    if (icon) {
      icon.after(countEl);
    } else {
      dislikeBtn.appendChild(countEl);
    }
    console.log("YTT: Dislike count element injected.");
  }

  dislikeBtn.style.setProperty("width", "auto", "important");
  dislikeBtn.style.setProperty("min-width", "auto", "important");
  dislikeBtn.style.setProperty("padding-right", "12px", "important");
  dislikeBtn.style.setProperty("display", "inline-flex", "important");
  dislikeBtn.style.setProperty("align-items", "center", "important");

  const parentVM = dislikeBtn.closest(
    "dislike-button-view-model, #segmented-dislike-button",
  );
  if (parentVM) {
    parentVM.style.setProperty("width", "auto", "important");
    parentVM.style.setProperty("min-width", "auto", "important");
  }

  dislikeBtn.classList.remove("yt-spec-button-shape-next--no-text");
}

function injectDislikeCount(forceFetch = false) {
  if (!dislikeCountSettings.enabled) return;

  const videoId = getVideoId();
  if (!videoId) return;

  // 1. Instant Cache Check (unless forced)
  if (
    !forceFetch &&
    lastFetchedDislikeData &&
    lastFetchedDislikeData.videoId === videoId &&
    dislikeCountSettings.enabled
  ) {
    renderDislikeCount(lastFetchedDislikeData);
    return;
  }

  // 2. Fetch Guard
  if (!forceFetch && dislikeFetchInProgress && videoId === lastDislikeVideoId)
    return;

  lastDislikeVideoId = videoId;
  dislikeFetchInProgress = true;

  fetchDislikeCount(videoId)
    .then((data) => {
      dislikeFetchInProgress = false;
      if (!data || typeof data !== "object") {
        console.warn("YTT: Dislike data is invalid or empty.");
        return;
      }

      lastFetchedDislikeData = { ...data, videoId };

      // Defensive check for settings object
      if (!dislikeCountSettings || dislikeCountSettings.enabled === false) {
        return;
      }

      console.log("YTT: Ready to render dislike count.");
      try {
        renderDislikeCount(lastFetchedDislikeData);
      } catch (err) {
        console.error("YTT: Failed to render dislike count:", err);
      }
    })
    .catch((err) => {
      dislikeFetchInProgress = false;
      console.error("YTT: Dislike fetch/process error:", err);
    });
}



// ─── init/bootstrap.js ─────────────────────────────────────────── 
// === Bootstrap: Initial calls, intervals, observers, event listeners ===

(async () => {
    // Wait for state to load from storage
    await initState();

    // Initial Run
    applyShortsBlockerState();
    applyDislikeCountState();
    injectStatsUI();
    setupFullscreenAutoHide();

    // Intervals
    const trackingInterval = setInterval(() => {
        try {
            if (window.yttContextInvalidated) {
                clearInterval(trackingInterval);
                return;
            }
            updateStats();
            checkBreakReminder();
        } catch (e) {
            if (e.message.includes('context invalidated')) {
                window.yttContextInvalidated = true;
                clearInterval(trackingInterval);
            }
        }
    }, 1000);

    const observer = new MutationObserver(() => {
        if (shortsBlockerSettings.enabled) blockShorts();
        applyDislikeCountState();
        // Ensure UI is re-injected if YouTube's SPA wipes it
        injectStatsUI();
    });

    observer.observe(document.documentElement, {
        childList: true,
        subtree: true
    });

    // Handle YouTube's custom navigation events
    window.addEventListener('yt-navigate-start', () => {
        // Final sync: use cached values, YouTube may have already reset the video element
        updateStats(lastVideoId, true);
    });

    window.addEventListener('yt-page-data-updated', () => {
        applyShortsBlockerState();
        applyDislikeCountState();
        injectStatsUI();
    });
    window.addEventListener('yt-navigate-finish', () => {
        applyShortsBlockerState();
        applyDislikeCountState();
        injectStatsUI();
    });
    window.addEventListener('popstate', () => {
        if (shortsBlockerSettings.enabled) blockShorts();
    });

    // Handle tab closure and backgrounding
    document.addEventListener('visibilitychange', () => {
        if (document.visibilityState === 'hidden') {
            updateStats(undefined, true);
        }
    });

    window.addEventListener('beforeunload', () => {
        updateStats(undefined, true);
    });
})();


